class Solution:
    def leastInterval(self, tasks, n):
        # Independent simulation: repeatedly pick the available task with the most
        # remaining count, respecting the cooldown window.
        from collections import Counter, deque
        import heapq
        cnt = Counter(tasks)
        heap = [-c for c in cnt.values()]
        heapq.heapify(heap)
        time = 0
        cooldown = deque()  # (ready_time, remaining)
        while heap or cooldown:
            time += 1
            if cooldown and cooldown[0][0] == time:
                heapq.heappush(heap, cooldown.popleft()[1])
            if heap:
                rem = heapq.heappop(heap) + 1
                if rem < 0:
                    cooldown.append((time + n + 1, rem))
        return time

