var leastInterval = function(tasks, n) {
    const counts = {};
    for (const t of tasks) counts[t] = (counts[t] || 0) + 1;
    let f = 0;
    for (const t in counts) f = Math.max(f, counts[t]);
    let k = 0;
    for (const t in counts) if (counts[t] === f) k++;
    return Math.max(tasks.length, (f - 1) * (n + 1) + k);
};
